var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"21:13 ARC-KP1 \\n어느 폐건물 \\n<color=#ff3636>사건 발생</color> 11시간 경과","JPN":"21:13 ARC-KP1 \\nとある廃墟\\n<color=#ff3636>事件発生から</color>11時間経過","ENG":"21:13 ARC-KP1\\nUnknown Abandoned Building\\n11 hours after <color=#ff3636>Incident</color>","TWN":"21:13 ARC-KP1\\n某個廢棄建築\\n<color=#ff3636>事件發生</color>經過11小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"역시나 여기로 왔구나! <color=#ffd34c>반드시 멸해야만 하는 악</color>!","JPN":"やっぱりここに来たな！　<color=#ffd34c>滅ぼすべき悪</color>め！","ENG":"I knew you’d show your face! <color=#ffd34c>The evil that must be destroyed</color>!","TWN":"我就知道你會來這裡！<color=#ffd34c>該死的惡人</color>！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"파사의 목소리가 속삭인 대로야!","JPN":"破邪の声が囁いたとおりだ！","ENG":"It’s just as the Voice of Evil Eradication said!","TWN":"破邪之聲說的果然沒錯！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……기다리고 있었습니다, 아가씨.","JPN":"……お待ちしていました、お嬢様。","ENG":"I was hoping to see you, Miss.","TWN":"……小姐，我一直在等你。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니…….","JPN":"ホノカさん……","ENG":"Jin...","TWN":"李珍姐……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그동안 곰곰이 생각해 봤어요.","JPN":"さきほどまで、じっくりと考えていました。","ENG":"I’ve thought long and hard about it.","TWN":"這段時間我反覆思想，"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부회장님……. 그리고 메카닉스 대표가 왜 살해당했는지.","JPN":"副会長……そしてメカニックス代表がなぜ殺されたのか。","ENG":"About why you would murder the Vice Chairman... and the CEO of Mechanics.","TWN":"副會長……還有機械代表，為何會遭到殺害？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"범인은 자신이 차기 회장이 되는 데 걸림돌인 인물들을 노렸습니다.","JPN":"犯人は自分が次期会長になるために邪魔となる人物を狙っていると思います。","ENG":"The murderer assassinated those who were obstructions in the path to becoming President.","TWN":"犯人是想要除掉那些會妨礙他成為會長的絆腳石。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부회장님은 순순히 권력에서 손을 뗄 분이 아니셨죠.","JPN":"副会長は、素直に権力から手を引くような方ではありませんでした。","ENG":"Vice Chairman wasn’t someone who would give up his power that easily.","TWN":"副會長不是會乖乖交出權力的人。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"메카닉스 대표는 신씨 집안에 등을 돌린 이사회가 차기 회장으로 눈여겨 보던 후보였고요.","JPN":"メカニックス代表もヒメノ家に背を向けた理事会が\\n次期会長として注目していた候補でした。","ENG":"The CEO of Mechanics was the board’s preferred choice, even though they turned their backs on the Shin family.","TWN":"而機械代表是討厭沈氏家族的董事會所支持的人選。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그러니 다음은 실적으로 주목 받은 알파트릭스 <color=#ffd34c>일렉트로닉스</color> 대표일 겁니다.","JPN":"ですので、次はその実績で注目されていたアルファトリックス・<color=#ffd34c>エレクトロニクス</color>代表でしょう。","ENG":"So naturally, the next target was going to be the CEO of Alphatrix’s <color=#ffd34c>Electronics</color>.","TWN":"最後則是以能力取勝的阿爾法崔克斯<color=#ffd34c>電子</color>代表。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아마 범인에게는 부회장님이나 이사회 같은 내부의 지지세력이 없었겠죠.","JPN":"おそらく犯人には副会長や理事会のような、グループ内部の支持勢力がいなかったのでしょうね。","ENG":"I assume that whoever’s behind this didn’t have any supporters like the Vice Chairman or the board of directors.","TWN":"犯人很可能沒有得到副會長或是董事會的支持。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그렇다면 이런 극단적인 방법을 택한 이유도 납득할 수 있습니다.","JPN":"それであれば、このような極端な方法を選んだ理由も納得できます。","ENG":"If that’s the case, all of this makes sense.","TWN":"因此，只能選擇這種極端的方法，如此也說得過去吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……이진 언니 말대로, 범인의 다음 타겟은 일렉트로닉스 대표님이에요.","JPN":"……ホノカさんの言うとおり、犯人の次のターゲットはエレクトロニクス代表です。","ENG":"Like you said, Jin. The next target is the CEO of Electronics.","TWN":"……如同照李珍姐所說的，犯人的下一個目標是電子代表。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어서 막으러 가지 않으면 또 사람이 죽고 말 거예요.","JPN":"急いで阻止しないと、また人が亡くなってしまいます。","ENG":"If I don’t go over there now, that person will die.","TWN":"不趕快去阻止的話，又會有人犧牲的！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"ですから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러니까, 길을 비켜주세요. 이진 언니.","JPN":"ですから道を開けてください、ホノカさん。","ENG":"So please, Jin. Get out of my way.","TWN":"所以李珍姐，請你讓開！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"일렉트로닉스에는 이미 증강현실 간섭기가 작동 중입니다.","JPN":"エレクトロニクスにはすでに拡張現実干渉機が作動しています。","ENG":"Electronics already activated the augmented reality jammers.","TWN":"電子內正在啟動擴增實境干涉器。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"다시 말해, 이대로 기다려 주시면 아가씨께서 분신으로 사건을 일으켰다는 주장은 힘을 잃을 겁니다.","JPN":"つまり、このままお待ちいただければ、\\nお嬢様が分身で事件を起こしたという主張は無効になるでしょう。","ENG":"In other words, if you stay here, the claim that your clones were responsible for all of the murders will fall apart.","TWN":"也就是說，只要再等一下，主張小姐是利用分身犯案的說法，自然就會站不住腳。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"잠깐만요, 이진 언니! 그러면 일렉트로닉스 대표님은……!","JPN":"待ってください、ホノカさん！　それではエレクトロニクス代表は……！","ENG":"Wait, Jin! Then what about the CEO of Electronics...?!","TWN":"可是李珍姐！萬一電子代表……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그럼 이대로 또 말도 안 되는 억지에 당하시려고요?","JPN":"では、こんなデタラメな強弁をそのままにされるおつもりですか？","ENG":"Do you want to take the fall again?","TWN":"難道你想繼續背負著污名嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이노베이션으로 쫓겨나셨을 때처럼?!","JPN":"イノベーションに追い出された時のように！","ENG":"Like the time they banished you to Innovation?!","TWN":"就像你被趕到改革的時候一樣？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"언니……!","JPN":"ホノカさん……！","ENG":"Jin...!","TWN":"李珍姐……！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……나는 그동안 널 쭉 지켜봐 왔어, 신지아. 더 이상 바보처럼 굴지 마.","JPN":"……ユイ、私は今までずっとあなたを見守ってきたわ。\\nこれ以上馬鹿な真似はしないで。","ENG":"I’ve been watching you all this time, Shin Jia. Stop making foolish decisions.","TWN":"……沈佳，這段時間我一直在觀察你，拜託你不要再像個笨蛋一樣。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이대로 기다려. 네가 손쓸 수 없는 상황에서 사건이 터지면 아무도 네게 뭐라고 못할 거야.","JPN":"大人しく待ってて。あなたが動けない状況で事件が起きたら、\\n誰もあなたに罪をなすりつけることはできなくなるわ。","ENG":"Just stay put. If the assassination still happens while you’re here with us, they can’t say it’s your fault anymore.","TWN":"你再等一下，只要證明事件是在你無法動手腳的情況下發生的，那誰也不能再說你什麼！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……네가 나를 죽이려 하지 않았다는 사실도 증명될 테고.","JPN":"……あなたが私を殺そうとなんてしていなかった事実も証明されるだろうし。","ENG":"...And it proves that you didn’t try to kill me.","TWN":"……也可以證明，你沒有想殺我！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"잠깐! 아줌마 지금 무슨 얘기를 하는 거야? 범인 잡는 걸 도와 준다며!","JPN":"ちょっと！　おばさん、それなんの話？\\n犯人を捕まえるのを手伝ってくれるって言ったよね！","ENG":"Hold it! What’re you talking about? I thought you said you’d help us catch the killer!","TWN":"先等一下！這位大嬸，你現在是在說什麼？你不是要來幫我抓犯人的嗎！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"맞아요. 용의자의 유죄를 증명하는 것도 필요하지 않나요?","JPN":"そうです。容疑者の罪を証明することも必要ではありませんか？","ENG":"I did, and I am. However, don’t we also need to prove that the suspect is guilty?","TWN":"沒錯，難道你不需要證明嫌犯是有罪的嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그, 그런가…… 가 아니라 말장난 하지 말구!","JPN":"そ、そうかな……じゃなくて、とぼけないで！","ENG":"D-do we...? Hey! That’s not what we agreed to!","TWN":"是這樣說嗎…… 你少呼攏我喔！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만…… 제가 언니 말대로 하면 일렉트로닉스 대표님은요?","JPN":"ですが……私がホノカさんの言うとおりにすると、エレクトロニクス代表は？","ENG":"But still... If I stay here, what will happen to the CEO of Electronics?","TWN":"可是……萬一我聽李珍姐的話，那電子代表怎麼辦？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 증명은 일렉트로닉스 대표님의 안전을 담보로 하는 것 아닌가요?","JPN":"その証明は、エレクトロニクス代表の安全を担保とするものではありませんか？","ENG":"You want to prove my innocence by putting someone else’s life on the line?","TWN":"證明我無罪的前提，是要犧牲電子代表的性命嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 손 놓고 가만히 있을 수 없어요.","JPN":"黙って待っているわけにはいきません。","ENG":"I can’t and won’t let that happen.","TWN":"我無法坐視不管！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니가 살인을 방관하는 사람이 되게 놔두긴 싫으니까요.","JPN":"ホノカさんが殺人を傍観する人になってしまうのは嫌です。","ENG":"Because I don't want you, Jin, to be a bystander in a murder.","TWN":"我不希望任由李珍姐成為殺人事件的旁觀者！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"신지아!!","JPN":"ユイ！！","ENG":"Shin Jia!!","TWN":"沈佳！！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……읏! 초원 양!?","JPN":"……うっ！　ナオさん！？","ENG":"...Ngh! Chowon?!","TWN":"……唔！初源？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"맞출 각오로 쐈는데 반사신경이 좋으시네요, 실장님.","JPN":"当てるつもりで撃ったのですが。反射神経が優れていますね、室長。","ENG":"That wasn’t a warning shot. Looks like you still got it, eh, Chief?","TWN":"我是瞄準你發射的，沒想到室長的反射神經很好嘛。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L14_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"좋아, 아슬아슬하게 정시 도착!","JPN":"よし、ギリギリ定時到着！","ENG":"Yes! Just in the nick of time!","TWN":"還好，千鈞一髮之際準時抵達！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여, 여러분? 잡혀 계신 것 아니었어요?","JPN":"み、皆さん！？　捕まっていると思いました！","ENG":"W-weren’t you all captured?","TWN":"大…大家？你們不是都被抓了嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"해후는 상황이 정리된 다음에 나누기로 하지.","JPN":"再会の喜びは状況が落ち着いてから味わうとしよう。","ENG":"We can talk about that after business is done here.","TWN":"詳細的情形等之後再說吧！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"가 보세요, 리더. 저 두 사람은 저희가 막겠습니다.","JPN":"ここは任せてください、リーダー。あの二人は私たちで止めます。","ENG":"Go, Leader. We’ll hold those two for you.","TWN":"你去吧，老大！那兩個人交給我們。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"탈출했다는 소식은 들었어, 악의 졸개들!","JPN":"脱出したという知らせは聞いていたぞ、悪の手先たちよ！","ENG":"I heard you escaped, henchmen of evil!","TWN":"我有收到你們越獄的消息，邪惡的跟班！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"하지만 방해하게 내버려 둘 거라는 생각은 아니겠지?","JPN":"だが、邪魔をさせるわけにいかないのだ！","ENG":"But you really don’t think I’m going to let her get away now, do you?","TWN":"不過你們以為，我會乖乖放人嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"훗. 각오해라, 동생이여. 이번에야말로 위아래를 정할 차례다.","JPN":"フッ。覚悟しろ、妹よ。今度こそ上下をはっきりさせる時だ。","ENG":"Pfft. En guard, little sister. It’s time we settled this once and for all.","TWN":"哼，覺悟吧，妹妹！這次就來決定誰才是老大吧！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"내가 이긴 거잖아! 얼렁뚱땅 넘어가려고 하지 마, 진짜!","JPN":"私が勝ったじゃん！　ごまかそうとしないでよ、もう！","ENG":"Hey! I won and you lost! Don't try to pretend that didn't happen!","TWN":"明明就是我贏！別想給我耍花招！可惡！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"신지아! 가면 안 돼!!","JPN":"ユイ！　行かないで！！","ENG":"Shin Jia! You mustn’t go!!","TWN":"沈佳！你不准走！！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"미안해요, 이진 언니.","JPN":"ごめんなさい、ホノカさん。","ENG":"I’m sorry, Jin...","TWN":"李珍姐，對不起。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만……. 곤경에 빠진 사람을 외면해선 안 되니까요.","JPN":"ですが、困っている人がいたら見て見ぬふりをしてはいけないので。","ENG":"But... I should help those in trouble.","TWN":"可是我……不可以對陷入困境的人視而不見。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};